prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(?modelId = "1f1b01e0a85340689b6df314b32bb4b6" || ?origId = "1f1b01e0a85340689b6df314b32bb4b6")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(STR(?normId), "1f1b01e0a85340689b6df314b32bb4b6") || 
         CONTAINS(STR(?origId), "1f1b01e0a85340689b6df314b32bb4b6") ||
         CONTAINS(STR(?model), "1f1b01e0a85340689b6df314b32bb4b6"))
}
LIMIT 25
